import{_ as l,o as a,c as s,a9 as e}from"./chunks/framework.STMWz9Nm.js";const c=JSON.parse('{"title":"序列化与通信协议","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/13-Dubbo学习/04-序列化与通信协议.md","filePath":"语言/java/13-Dubbo学习/04-序列化与通信协议.md","lastUpdated":1777177198000}'),h={name:"语言/java/13-Dubbo学习/04-序列化与通信协议.md"};function n(t,i,r,p,d,k){return a(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="序列化与通信协议" tabindex="-1">序列化与通信协议 <a class="header-anchor" href="#序列化与通信协议" aria-label="Permalink to “序列化与通信协议”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>很多人学 RPC 时，前面几章都还能跟上：</p><ul><li>有 Provider</li><li>有 Consumer</li><li>有注册中心</li><li>有负载均衡</li></ul><p>但一到“序列化”和“通信协议”，就开始觉得抽象。</p><p>其实先别把它想复杂，你可以这样理解：</p><ul><li><strong>序列化</strong>：把 Java 对象变成可以在网络上传输的字节数据</li><li><strong>反序列化</strong>：把收到的字节数据再还原成对象</li><li><strong>通信协议</strong>：规定这些字节怎么组织、怎么识别、怎么解析</li></ul><p>如果只记一句话：</p><blockquote><p><strong>序列化解决“对象怎么传”，协议解决“这段数据该怎么读”。</strong></p></blockquote><p>例如一次 Dubbo 调用里，Consumer 想传一个请求对象：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UserQuery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1001L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这个对象本身不能直接在网络里“原样飞过去”。</p><p>必须先做两件事：</p><ol><li>把对象编码成字节流</li><li>规定接收方怎么从字节流中正确拆出一条完整消息</li></ol><p>这就是这一层存在的意义。</p><hr><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>这一层看似底层，实际上直接影响：</p><ul><li>性能</li><li>稳定性</li><li>兼容性</li><li>调试难度</li></ul><p>它决定了这些现实问题：</p><ul><li>为什么有些 RPC 框架更快</li><li>为什么字段一改，调用就可能炸掉</li><li>为什么有时日志只看到“反序列化失败”</li><li>为什么协议一旦定下来，不能随便乱改</li></ul><p>换句话说：</p><blockquote><p><strong>你看到的是一次方法调用，框架看到的是一段二进制消息的编码与解码。</strong></p></blockquote><p>如果这一层设计或使用不当，哪怕你的业务逻辑完全没问题，调用也照样会失败。</p><hr><h2 id="_3-先建立最核心的直觉" tabindex="-1">3. 先建立最核心的直觉 <a class="header-anchor" href="#_3-先建立最核心的直觉" aria-label="Permalink to “3. 先建立最核心的直觉”">​</a></h2><p>可以把一次 RPC 调用想成寄快递。</p><h3 id="序列化像什么" tabindex="-1">序列化像什么 <a class="header-anchor" href="#序列化像什么" aria-label="Permalink to “序列化像什么”">​</a></h3><p>像把物品装箱、贴标签：</p><ul><li>原始对象不能直接发</li><li>要先打包成标准格式</li><li>对方收到后才能拆开还原</li></ul><h3 id="协议像什么" tabindex="-1">协议像什么 <a class="header-anchor" href="#协议像什么" aria-label="Permalink to “协议像什么”">​</a></h3><p>像快递单和包装规范：</p><ul><li>这是谁寄的</li><li>发到哪里</li><li>包裹有多长</li><li>里面是什么类型</li><li>用什么方式解码</li></ul><p>如果没有协议规范，会发生什么？</p><ul><li>收件方根本不知道从哪里开始读</li><li>不知道一条消息什么时候结束</li><li>不知道字段如何解释</li></ul><p>所以你可以先记住：</p><ul><li><strong>序列化更像“对象打包”</strong></li><li><strong>协议更像“打包规则 + 读取规则”</strong></li></ul><hr><h2 id="_4-为什么对象不能直接传" tabindex="-1">4. 为什么对象不能直接传 <a class="header-anchor" href="#_4-为什么对象不能直接传" aria-label="Permalink to “4. 为什么对象不能直接传”">​</a></h2><p>因为网络底层传输的不是 Java 对象，而是字节。</p><p>你在代码里写的是：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">userService.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getById</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1001L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>但到网络层，必须变成类似这样的信息：</p><ul><li>调用的是哪个接口</li><li>调用的是哪个方法</li><li>参数类型是什么</li><li>参数值是什么</li><li>请求 ID 是多少</li><li>是否需要返回值</li></ul><p>然后再编码成一段字节流发出去。</p><p>Provider 收到后，再按同样规则解码，还原出：</p><ul><li>方法名</li><li>参数列表</li><li>调用上下文</li></ul><p>然后才能真正执行本地方法。</p><p>所以序列化从来不只是“对象转字节”这么简单，它还关系到：</p><ul><li>字段结构</li><li>类型信息</li><li>版本兼容</li><li>安全边界</li></ul><hr><h2 id="_5-一条-rpc-消息通常包含什么" tabindex="-1">5. 一条 RPC 消息通常包含什么 <a class="header-anchor" href="#_5-一条-rpc-消息通常包含什么" aria-label="Permalink to “5. 一条 RPC 消息通常包含什么”">​</a></h2><p>你可以先用最粗粒度理解一条消息结构：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>| 协议头 | 消息体 |</span></span></code></pre></div><p>再展开一点看：</p><h3 id="_5-1-协议头可能包含" tabindex="-1">5.1 协议头可能包含 <a class="header-anchor" href="#_5-1-协议头可能包含" aria-label="Permalink to “5.1 协议头可能包含”">​</a></h3><ul><li>魔数（判断是不是这个协议）</li><li>协议版本</li><li>消息类型（请求/响应）</li><li>序列化方式</li><li>请求 ID</li><li>消息长度</li></ul><h3 id="_5-2-消息体可能包含" tabindex="-1">5.2 消息体可能包含 <a class="header-anchor" href="#_5-2-消息体可能包含" aria-label="Permalink to “5.2 消息体可能包含”">​</a></h3><ul><li>接口名</li><li>方法名</li><li>参数类型</li><li>参数值</li><li>返回值</li><li>异常信息</li></ul><p>这样设计的好处是：</p><ul><li>接收方知道怎么解析</li><li>能区分请求和响应</li><li>能根据请求 ID 做请求响应匹配</li><li>能根据序列化类型选择对应解码器</li></ul><hr><h2 id="_6-什么是协议头里的-魔数" tabindex="-1">6. 什么是协议头里的“魔数” <a class="header-anchor" href="#_6-什么是协议头里的-魔数" aria-label="Permalink to “6. 什么是协议头里的“魔数””">​</a></h2><p>这是协议里一个很常见的概念。</p><p>魔数可以理解成：</p><ul><li>一段固定标记</li><li>用来快速识别“这是不是我这个协议的数据”</li></ul><p>通俗理解：</p><ul><li>像文件格式里的签名</li><li>或像快递包裹上的特定标识</li></ul><p>它的作用是：</p><ul><li>避免把错误数据按错误协议去解</li><li>帮助快速判断数据是否合法</li></ul><hr><h2 id="_7-常见序列化关注点" tabindex="-1">7. 常见序列化关注点 <a class="header-anchor" href="#_7-常见序列化关注点" aria-label="Permalink to “7. 常见序列化关注点”">​</a></h2><p>很多人一说序列化，只想到“快不快”。</p><p>其实至少要同时看 4 件事：</p><ol><li>编码速度</li><li>解码速度</li><li>体积大小</li><li>兼容性</li></ol><h3 id="_7-1-速度" tabindex="-1">7.1 速度 <a class="header-anchor" href="#_7-1-速度" aria-label="Permalink to “7.1 速度”">​</a></h3><p>序列化慢，会拖累 CPU。</p><h3 id="_7-2-体积" tabindex="-1">7.2 体积 <a class="header-anchor" href="#_7-2-体积" aria-label="Permalink to “7.2 体积”">​</a></h3><p>编码后数据太大，会浪费带宽，也会拉高延迟。</p><h3 id="_7-3-兼容性" tabindex="-1">7.3 兼容性 <a class="header-anchor" href="#_7-3-兼容性" aria-label="Permalink to “7.3 兼容性”">​</a></h3><p>这是实战里最容易被忽略的点。</p><p>比如你今天发的是：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UserDTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Long id;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    String name;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>明天改成：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UserDTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Long id;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    String name;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Integer age;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>如果 Provider 和 Consumer 版本不一致，就可能出现：</p><ul><li>新字段丢失</li><li>反序列化失败</li><li>类型不匹配</li></ul><p>所以序列化方案不是只看“跑分”，还要看“演进时稳不稳”。</p><hr><h2 id="_8-dubbo-为什么不能随意改协议" tabindex="-1">8. Dubbo 为什么不能随意改协议 <a class="header-anchor" href="#_8-dubbo-为什么不能随意改协议" aria-label="Permalink to “8. Dubbo 为什么不能随意改协议”">​</a></h2><p>因为协议一旦两端约定好，就是双方沟通的共同语言。</p><p>如果 Consumer 认为：</p><ul><li>前 2 个字节是魔数</li><li>后 4 个字节是长度</li><li>接下来是请求 ID</li></ul><p>而 Provider 却按另一套规则解释，那结果一定是：</p><ul><li>解码失败</li><li>消息错位</li><li>请求根本读不出来</li></ul><p>所以协议不是“想怎么改就怎么改的内部实现细节”，而是：</p><blockquote><p><strong>通信双方必须长期共同遵守的一套规则。</strong></p></blockquote><p>这也是为什么协议演进一定要考虑兼容性。</p><hr><h2 id="_9-一个最小例子-请求是怎么被编码理解的" tabindex="-1">9. 一个最小例子：请求是怎么被编码理解的 <a class="header-anchor" href="#_9-一个最小例子-请求是怎么被编码理解的" aria-label="Permalink to “9. 一个最小例子：请求是怎么被编码理解的”">​</a></h2><p>假设业务代码是：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">userService.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getById</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1001L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>框架层可能需要抽象出类似这样的请求：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;interface&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.demo.UserService&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;method&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;getById&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;parameterTypes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java.lang.Long&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;requestId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">123456</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>然后再把这段结构编码成字节。</p><p>接收方收到后，再还原回来，才能定位到：</p><ul><li>调哪个服务</li><li>调哪个方法</li><li>参数是什么</li></ul><p>所以你看到的是：</p><ul><li><code>getById(1001L)</code></li></ul><p>底层实际要处理的是：</p><ul><li>一份结构化请求消息的编码与解码</li></ul><hr><h2 id="_10-动手验证-从-能调通-到-能看懂" tabindex="-1">10. 动手验证：从“能调通”到“能看懂” <a class="header-anchor" href="#_10-动手验证-从-能调通-到-能看懂" aria-label="Permalink to “10. 动手验证：从“能调通”到“能看懂””">​</a></h2><p>如果你本地有 Dubbo 项目，可以做下面几步实验。</p><h3 id="_10-1-正常跑通一次调用" tabindex="-1">10.1 正常跑通一次调用 <a class="header-anchor" href="#_10-1-正常跑通一次调用" aria-label="Permalink to “10.1 正常跑通一次调用”">​</a></h3><p>先保证 Consumer 和 Provider 能正常调用。</p><h3 id="_10-2-打印请求对象和返回对象" tabindex="-1">10.2 打印请求对象和返回对象 <a class="header-anchor" href="#_10-2-打印请求对象和返回对象" aria-label="Permalink to “10.2 打印请求对象和返回对象”">​</a></h3><p>观察：</p><ul><li>方法调用前的 Java 对象长什么样</li><li>调用返回后的对象长什么样</li></ul><p>思考中间发生了什么：</p><ul><li>对象在网络里不可能原样存在</li><li>中间一定经历过编码和解码</li></ul><h3 id="_10-3-故意修改-dto-字段" tabindex="-1">10.3 故意修改 DTO 字段 <a class="header-anchor" href="#_10-3-故意修改-dto-字段" aria-label="Permalink to “10.3 故意修改 DTO 字段”">​</a></h3><p>例如新增一个字段：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">private</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Integer age;</span></span></code></pre></div><p>然后让 Consumer 和 Provider 保持不同版本，观察：</p><ul><li>调用是否还能成功</li><li>新字段是否丢失</li><li>是否出现兼容性问题</li></ul><p>这一步能帮你真正理解：</p><ul><li>协议兼容不是理论问题，而是升级时马上会碰到的问题</li></ul><hr><h2 id="_11-为什么字段变更很危险" tabindex="-1">11. 为什么字段变更很危险 <a class="header-anchor" href="#_11-为什么字段变更很危险" aria-label="Permalink to “11. 为什么字段变更很危险”">​</a></h2><p>很多人以为 DTO 改个字段只是“小事”。</p><p>但在 RPC 里，字段变更可能影响：</p><ul><li>老版本 Consumer</li><li>老版本 Provider</li><li>序列化兼容</li><li>反序列化结果</li></ul><p>常见危险操作包括：</p><ul><li>删除字段</li><li>修改字段类型</li><li>调整字段语义</li><li>不做版本隔离直接上线</li></ul><p>相对更稳妥的思路通常是：</p><ul><li>优先新增字段，而不是粗暴改旧字段语义</li><li>做灰度验证</li><li>确保两端兼容窗口存在</li></ul><hr><h2 id="_12-最容易踩的坑" tabindex="-1">12. 最容易踩的坑 <a class="header-anchor" href="#_12-最容易踩的坑" aria-label="Permalink to “12. 最容易踩的坑”">​</a></h2><h3 id="_12-1-只关心速度-不关心兼容性" tabindex="-1">12.1 只关心速度，不关心兼容性 <a class="header-anchor" href="#_12-1-只关心速度-不关心兼容性" aria-label="Permalink to “12.1 只关心速度，不关心兼容性”">​</a></h3><p>这是最典型的错误。</p><p>序列化跑得再快，如果版本一升级就炸，线上成本会非常高。</p><h3 id="_12-2-dto-字段随意改" tabindex="-1">12.2 DTO 字段随意改 <a class="header-anchor" href="#_12-2-dto-字段随意改" aria-label="Permalink to “12.2 DTO 字段随意改”">​</a></h3><p>尤其是共享接口模型，一旦随便改字段类型或删除字段，就容易让老调用方出问题。</p><h3 id="_12-3-看到-反序列化失败-只怀疑网络" tabindex="-1">12.3 看到“反序列化失败”只怀疑网络 <a class="header-anchor" href="#_12-3-看到-反序列化失败-只怀疑网络" aria-label="Permalink to “12.3 看到“反序列化失败”只怀疑网络”">​</a></h3><p>很多时候网络没问题，真正的问题是：</p><ul><li>DTO 结构不一致</li><li>协议版本不匹配</li><li>序列化方式不一致</li></ul><h3 id="_12-4-不理解协议头字段的作用" tabindex="-1">12.4 不理解协议头字段的作用 <a class="header-anchor" href="#_12-4-不理解协议头字段的作用" aria-label="Permalink to “12.4 不理解协议头字段的作用”">​</a></h3><p>如果连：</p><ul><li>长度字段是干嘛的</li><li>请求 ID 是干嘛的</li><li>消息类型是干嘛的</li></ul><p>都不理解，排查编解码问题会很痛苦。</p><hr><h2 id="_13-一套排查思路" tabindex="-1">13. 一套排查思路 <a class="header-anchor" href="#_13-一套排查思路" aria-label="Permalink to “13. 一套排查思路”">​</a></h2><p>以后你遇到“Dubbo 调用报编解码/序列化错误”，可以按这个顺序排：</p><ol><li>Consumer 和 Provider 的接口版本是否一致</li><li>DTO 字段结构是否兼容</li><li>序列化方式是否一致</li><li>协议版本是否兼容</li><li>是否有字段类型变更或删除</li><li>是否能从日志里定位到具体哪个类/字段反序列化失败</li></ol><p>这个顺序比一上来就怀疑“网络不稳”更有效。</p><hr><h2 id="_14-练习建议" tabindex="-1">14. 练习建议 <a class="header-anchor" href="#_14-练习建议" aria-label="Permalink to “14. 练习建议”">​</a></h2><h3 id="练习-1-画一张消息结构图" tabindex="-1">练习 1：画一张消息结构图 <a class="header-anchor" href="#练习-1-画一张消息结构图" aria-label="Permalink to “练习 1：画一张消息结构图”">​</a></h3><p>自己画出：</p><ul><li>协议头里有哪些字段</li><li>消息体里有哪些内容</li></ul><h3 id="练习-2-设计一个最小请求模型" tabindex="-1">练习 2：设计一个最小请求模型 <a class="header-anchor" href="#练习-2-设计一个最小请求模型" aria-label="Permalink to “练习 2：设计一个最小请求模型”">​</a></h3><p>例如给 <code>getUserById</code> 设计一份最小 RPC 请求结构，包含：</p><ul><li>接口名</li><li>方法名</li><li>参数类型</li><li>参数值</li><li>请求 ID</li></ul><h3 id="练习-3-模拟兼容性问题" tabindex="-1">练习 3：模拟兼容性问题 <a class="header-anchor" href="#练习-3-模拟兼容性问题" aria-label="Permalink to “练习 3：模拟兼容性问题”">​</a></h3><p>故意让 Consumer 和 Provider 的 DTO 不一致，然后观察：</p><ul><li>是否还能调通</li><li>哪些字段丢了</li><li>是否直接异常</li></ul><hr><h2 id="_15-自测问题" tabindex="-1">15. 自测问题 <a class="header-anchor" href="#_15-自测问题" aria-label="Permalink to “15. 自测问题”">​</a></h2><ul><li>序列化和通信协议分别解决什么问题？</li><li>为什么网络里传的不是 Java 对象本身？</li><li>协议头里为什么常常要有长度、请求 ID、消息类型这些字段？</li><li>为什么协议和 DTO 结构不能随意变动？</li><li>为什么说兼容性常常比“极限性能”更重要？</li></ul><hr><h2 id="_16-这一章你至少要带走什么" tabindex="-1">16. 这一章你至少要带走什么 <a class="header-anchor" href="#_16-这一章你至少要带走什么" aria-label="Permalink to “16. 这一章你至少要带走什么”">​</a></h2><p>如果你看完只记住 4 件事，就记这 4 件：</p><ol><li><strong>序列化解决的是“对象怎么变成字节”</strong></li><li><strong>协议解决的是“这些字节怎么组织、怎么识别、怎么解析”</strong></li><li><strong>RPC 稳定性不仅取决于网络，还取决于编解码和兼容性</strong></li><li><strong>字段演进和协议升级必须考虑兼容，否则很容易线上炸调用</strong></li></ol><p>把这一层理解透了，你再看 Dubbo 的协议、序列化和链路排障，就不会觉得它只是“底层黑魔法”了。</p>`,175)])])}const g=l(h,[["render",n]]);export{c as __pageData,g as default};
